<?php require_once 'db.php'; verify_csrf(); $token=$_GET['token']??$_POST['token']??''; $msg=$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $pass=$_POST['password']??''; $otp=trim($_POST['otp']??''); $st=pdo()->prepare('SELECT * FROM password_resets WHERE token=? AND otp=? AND used_at IS NULL AND expires_at>NOW()'); $st->execute([$token,$otp]); if(strlen($pass)>=6 && ($r=$st->fetch())){ pdo()->prepare('UPDATE users SET password=? WHERE id=?')->execute([password_hash($pass,PASSWORD_DEFAULT),$r['user_id']]); pdo()->prepare('UPDATE password_resets SET used_at=NOW() WHERE id=?')->execute([$r['id']]); $msg='Password reset successful. You may login.'; } else $err='Invalid/expired token, OTP, or short password.'; } app_header('Reset Password'); ?><section class="auth card"><h1>Reset Password</h1><p class="ok"><?=e($msg)?></p><p class="error"><?=e($err)?></p><form method="post"><?=csrf_field()?><input type="hidden" name="token" value="<?=e($token)?>"><input name="otp" placeholder="Email OTP" required><input name="password" type="password" placeholder="New password" required><button class="btn">Reset</button></form></section><?php app_footer(); ?>
